// Simple manual validation example
function validateUser(user) {
  if (typeof user.name !== 'string') throw new Error('Name must be a string');
  if (!user.address || typeof user.address.city !== 'string') throw new Error('Invalid address');
}

try {
  validateUser(user);
  console.log('User data is valid');
} catch (error) {
  console.error(error.message);
}

function updateUserCity(user, newCity) {
  return {
    ...user,
    address: {
      ...user.address,
      city: newCity
    }
  };
}

const newUser = updateUserCity(user, 'Chicago');
console.log(user.address.city); // 'New York'
console.log(newUser.address.city); // 'Chicago'

